-- Fix existing universities - update type to proper institution types
UPDATE universities 
SET type = CASE 
  WHEN name LIKE '%University of Applied Sciences%' OR name LIKE '%Hochschule%' THEN 'university_applied_sciences'
  WHEN name LIKE '%Technical University%' OR name LIKE '%University of Technology%' THEN 'technical_university'  
  WHEN name LIKE '%Art%' OR name LIKE '%Music%' OR name LIKE '%Design%' THEN 'art_music_university'
  ELSE 'university'
END
WHERE type = 'Public';

